var PROXY_PORT=8081;

// ===== STATS TRACKING =====
var minerStats = {
  status: 'idle',
  hashrate: 0,
  totalHashes: 0,
  acceptedShares: 0,
  rejectedShares: 0,
  connectedSince: null,
  lastJob: null,
  currentDifficulty: 0,
  walletAddress: WALLET_ADDRESS,
  uptimeMs: 0
};
var hashCount = 0;
var hashStartTime = 0;

function updateStats(key, value) {
  minerStats[key] = value;
  postMessage({ target: 'custom', userData: { message: 'stats_update', stats: JSON.parse(JSON.stringify(minerStats)) } });
}

function recordHash() {
  hashCount++;
  minerStats.totalHashes++;
  if (hashStartTime === 0) hashStartTime = Date.now();
  var elapsed = (Date.now() - hashStartTime) / 1000;
  if (elapsed > 0) {
    minerStats.hashrate = Math.round(hashCount / elapsed);
  }
  // Update stats every 5 hashes to avoid spam
  if (minerStats.totalHashes % 5 === 0) {
    updateStats('hashrate', minerStats.hashrate);
  }
}

// Patch cn_hash to count hashes
var originalCnHash = cn_hash;
cn_hash = function(blob, len, targetLow, targetHigh, height) {
  recordHash();
  return originalCnHash(blob, len, targetLow, targetHigh, height);
};
// ===== END STATS TRACKING =====

